with:
  def predict(triples: list[Triple]) -> str:
      """Generate a natural‑language sentence from a list of Triple objects or plain tuples."""
      if not triples:
          return ""
      # Allow input as plain (subject, predicate, object) tuples as well as Triple objects
      if not isinstance(triples[0], Triple):
          triples = [Triple(*t) for t in triples]
